/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"package-container\">\n    <div class=\"package-header\">\n        <div class=\"container\">\n            <h1>core</h1>\n            <p class=\"content en\">Comprehensive utility library for TypeScript/JavaScript projects</p>\n            <p class=\"content ko\">TypeScript/JavaScript 프로젝트를 위한 포괄적인 유틸리티 라이브러리</p>\n            <div class=\"package-actions\">\n                <a href=\"https://www.npmjs.com/package/@dooboostore/core\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n                </a>\n                <a href=\"https://github.com/dooboostore-develop/packages\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n                </a>\n            </div>\n        </div>\n    </div>\n    <div class=\"package-content\">\n        <div class=\"container\">\n            <!-- Installation -->\n            <section class=\"section\">\n                <h2 id=\"installation\">Installation</h2>\n                <p class=\"content en\">Install the package:</p>\n                <p class=\"content ko\">패키지를 설치하세요:</p>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">npm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">npm install @dooboostore/core</code></pre>\n                </div>\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">pnpm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">pnpm add @dooboostore/core</code></pre>\n                </div>\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">yarn</span>\n                    </div>\n                    <pre><code class=\"language-bash\">yarn add @dooboostore/core</code></pre>\n                </div>\n            </section>\n\n            <!-- Features -->\n            <section class=\"section\">\n                <h2 id=\"features\">Features</h2>\n                <div class=\"features-grid\">\n                    <div class=\"feature-item\">\n                        <h3>Rich Utilities</h3>\n                        <p class=\"content en\">Vast collection of utilities for arrays, objects, strings, dates, and math operations</p>\n                        <p class=\"content ko\">배열, 객체, 문자열, 날짜, 수학 연산을 위한 방대한 유틸리티 컬렉션</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Type-Safe</h3>\n                        <p class=\"content en\">Written in TypeScript with powerful and flexible utility types</p>\n                        <p class=\"content ko\">강력하고 유연한 유틸리티 타입을 제공하는 TypeScript로 작성</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Asynchronous Toolkit</h3>\n                        <p class=\"content en\">Advanced tools for Promises, transactions, queues, and state wrappers</p>\n                        <p class=\"content ko\">Promise, 트랜잭션, 큐, 상태 래퍼를 위한 고급 도구</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Messaging System</h3>\n                        <p class=\"content en\">Observable pattern with RxJS-like operators for reactive programming</p>\n                        <p class=\"content ko\">반응형 프로그래밍을 위한 RxJS 스타일 연산자를 포함한 Observable 패턴</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>HTTP Client</h3>\n                        <p class=\"content en\">Flexible and extensible HTTP client framework with JSON/XML support</p>\n                        <p class=\"content ko\">JSON/XML 지원을 포함한 유연하고 확장 가능한 HTTP 클라이언트 프레임워크</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>2D/3D Geometry</h3>\n                        <p class=\"content en\">Comprehensive classes for points, vectors, shapes, and rendering engine</p>\n                        <p class=\"content ko\">점, 벡터, 도형, 렌더링 엔진을 위한 포괄적인 클래스</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>CSS Parsing</h3>\n                        <p class=\"content en\">Utilities for parsing and manipulating CSS rules and declarations</p>\n                        <p class=\"content ko\">CSS 규칙과 선언을 파싱하고 조작하는 유틸리티</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>OpenAPI Integration</h3>\n                        <p class=\"content en\">Type definitions and client generation helpers for OpenAPI specs</p>\n                        <p class=\"content ko\">OpenAPI 스펙을 위한 타입 정의와 클라이언트 생성 헬퍼</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Quick Start -->\n            <section class=\"section\">\n                <h2 id=\"quick-start\">Quick Start</h2>\n                \n                <h3 id=\"array-utils\">Array Utilities</h3>\n                <p class=\"content en\">Powerful array manipulation functions:</p>\n                <p class=\"content ko\">강력한 배열 조작 함수들:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; ArrayUtils &#125; from '@dooboostore/core/array/ArrayUtils';\n\nconst myArray = [1, 2, 3, 4, 5];\n\n// Shuffle the array\nconst shuffled = ArrayUtils.toShuffle(myArray);\nconsole.log(shuffled);\n\n// Pick a random element\nconst randomItem = ArrayUtils.pick(myArray);\nconsole.log(randomItem); // e.g., 3\n\n// Pick 3 random unique elements\nconst randomItems = ArrayUtils.pick(myArray, 3);\nconsole.log(randomItems); // e.g., [5, 1, 3]\n\n// Create 2D array\nconst grid = ArrayUtils.create2DArray(3, 3, 0);\nconsole.log(grid); // [[0,0,0], [0,0,0], [0,0,0]]\n\n// Set operations\nconst arr1 = [1, 2, 3, 4];\nconst arr2 = [3, 4, 5, 6];\nconst intersection = ArrayUtils.intersection(arr1, arr2);\nconsole.log(intersection); // [3, 4]</code></pre>\n                </div>\n\n                <h3 id=\"date-utils\">Date Utilities</h3>\n                <p class=\"content en\">Comprehensive date formatting and manipulation:</p>\n                <p class=\"content ko\">포괄적인 날짜 포맷팅과 조작:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; DateUtils &#125; from '@dooboostore/core/date/DateUtils';\n\nconst now = new Date();\n\n// Format a date\nconst formatted = DateUtils.format(now, 'yyyy-MM-dd HH:mm:ss');\nconsole.log(formatted); // \"2025-06-28 10:30:00\"\n\n// Get relative time\nconst fiveMinutesAgo = new Date(Date.now() - 5 * 60 * 1000);\nconst relative = DateUtils.relativeTime(fiveMinutesAgo);\nconsole.log(relative); // \"5 minutes ago\"\n\n// Date calculations\nconst tomorrow = DateUtils.addDays(now, 1);\nconst nextWeek = DateUtils.addWeeks(now, 1);\nconst nextMonth = DateUtils.addMonths(now, 1);\n\n// Compare dates\nconst isAfter = DateUtils.isAfter(tomorrow, now);\nconsole.log(isAfter); // true</code></pre>\n                </div>\n\n                <h3 id=\"http-fetcher\">HTTP Client</h3>\n                <p class=\"content en\">Flexible HTTP client with JSON and XML support:</p>\n                <p class=\"content ko\">JSON과 XML을 지원하는 유연한 HTTP 클라이언트:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; HttpJsonFetcher, HttpResponseError &#125; from '@dooboostore/core/fetch/HttpJsonFetcher';\n\nconst jsonFetcher = new HttpJsonFetcher&lt;any, any&gt;();\n\nasync function fetchData() &#123;\n  try &#123;\n    // GET request for JSON data\n    const user = await jsonFetcher.get(&#123;\n      target: `https://jsonplaceholder.typicode.com/users/1`\n    &#125;);\n    console.log('Fetched User:', user);\n\n    // POST request with JSON body\n    const newProduct = await jsonFetcher.postJson(&#123;\n      target: `https://dummyjson.com/products/add`,\n      config: &#123;\n        fetch: &#123;\n          body: &#123; title: 'New Awesome Gadget', price: 199.99 &#125;,\n        &#125;,\n      &#125;,\n    &#125;);\n    console.log('Created Product:', newProduct);\n\n  &#125; catch (error: any) &#123;\n    if (error instanceof HttpResponseError) &#123;\n      console.error('HTTP Error:', error.message, error.response?.status);\n    &#125; else &#123;\n      console.error('Generic Error:', error);\n    &#125;\n  &#125;\n&#125;</code></pre>\n                </div>\n\n                <h3 id=\"observables\">Observable & Operators</h3>\n                <p class=\"content en\">Reactive programming with RxJS-like operators:</p>\n                <p class=\"content ko\">RxJS 스타일 연산자를 사용한 반응형 프로그래밍:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; Observable &#125; from '@dooboostore/core/message/Observable';\nimport &#123; Subject &#125; from '@dooboostore/core/message/Subject';\nimport &#123; map &#125; from '@dooboostore/core/message/operators/map';\nimport &#123; filter &#125; from '@dooboostore/core/message/operators/filter';\nimport &#123; debounceTime &#125; from '@dooboostore/core/message/operators/debounceTime';\n\n// Create a simple Observable\nconst source&#36; = new Observable&lt;number&gt;(subscriber =&gt; &#123;\n  let count = 0;\n  const intervalId = setInterval(() =&gt; &#123;\n    subscriber.next(count++);\n    if (count &gt; 5) subscriber.complete();\n  &#125;, 100);\n  return () =&gt; clearInterval(intervalId);\n&#125;);\n\n// Transform and filter data\nsource&#36;.pipe(\n  filter(num =&gt; num % 2 === 0), // Only even numbers\n  map(num =&gt; `Number: &#36;&#123;num * 10&#125;`)\n).subscribe(&#123;\n  next: (data) =&gt; console.log(data),\n  complete: () =&gt; console.log('Completed!')\n&#125;);\n\n// Debounced search input\nconst searchInput&#36; = new Subject&lt;string&gt;();\nsearchInput&#36;.pipe(\n  debounceTime(500) // Wait for 500ms of inactivity\n).subscribe(searchText =&gt; &#123;\n  console.log('Searching for:', searchText);\n&#125;);</code></pre>\n                </div>\n            </section>\n\n            <!-- Core Modules -->\n            <section class=\"section\">\n                <h2 id=\"core-modules\">Core Modules</h2>\n                <p class=\"content en\">Comprehensive collection of utility modules:</p>\n                <p class=\"content ko\">포괄적인 유틸리티 모듈 컬렉션:</p>\n                \n                <div class=\"modules-grid\">\n                    <div class=\"module-item\">\n                        <h4>ArrayUtils</h4>\n                        <p class=\"content en\">Array manipulation, shuffling, random picking, 2D arrays, set operations</p>\n                        <p class=\"content ko\">배열 조작, 셔플, 랜덤 선택, 2D 배열, 집합 연산</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>ObjectUtils</h4>\n                        <p class=\"content en\">Deep copying, prototype inspection, property manipulation</p>\n                        <p class=\"content ko\">깊은 복사, 프로토타입 검사, 속성 조작</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>StringUtils</h4>\n                        <p class=\"content en\">String manipulation, padding, trimming, HTML unescaping</p>\n                        <p class=\"content ko\">문자열 조작, 패딩, 트리밍, HTML 언이스케이핑</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>DateUtils</h4>\n                        <p class=\"content en\">Date formatting, comparison, calculations, relative time</p>\n                        <p class=\"content ko\">날짜 포맷팅, 비교, 계산, 상대 시간</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>MathUtil</h4>\n                        <p class=\"content en\">Advanced math functions, Bezier curves, percentage calculations</p>\n                        <p class=\"content ko\">고급 수학 함수, 베지어 곡선, 백분율 계산</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>RandomUtils</h4>\n                        <p class=\"content en\">Random integers, decimals, UUIDs, hex colors generation</p>\n                        <p class=\"content ko\">랜덤 정수, 소수, UUID, 16진수 색상 생성</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>ConvertUtils</h4>\n                        <p class=\"content en\">JSON, Map, Object, URLSearchParams, FormData converters</p>\n                        <p class=\"content ko\">JSON, Map, Object, URLSearchParams, FormData 변환기</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>ValidUtils</h4>\n                        <p class=\"content en\">Type checking and validation functions</p>\n                        <p class=\"content ko\">타입 검사 및 검증 함수</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>Promises</h4>\n                        <p class=\"content en\">Promise utilities: sleep, settle, loop, transaction, Result.wrap</p>\n                        <p class=\"content ko\">Promise 유틸리티: sleep, settle, loop, transaction, Result.wrap</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>Observable & Operators</h4>\n                        <p class=\"content en\">RxJS-like reactive programming with 20+ operators</p>\n                        <p class=\"content ko\">20개 이상의 연산자를 포함한 RxJS 스타일 반응형 프로그래밍</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>Entity & Geometry</h4>\n                        <p class=\"content en\">2D/3D points, vectors, shapes, rendering engine with animations</p>\n                        <p class=\"content ko\">2D/3D 점, 벡터, 도형, 애니메이션을 포함한 렌더링 엔진</p>\n                    </div>\n                    <div class=\"module-item\">\n                        <h4>CssParser</h4>\n                        <p class=\"content en\">Parse, manipulate, and stringify CSS rules and declarations</p>\n                        <p class=\"content ko\">CSS 규칙과 선언을 파싱, 조작, 문자열화</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Advanced Features -->\n            <section class=\"section\">\n                <h2 id=\"advanced-features\">Advanced Features</h2>\n                \n                <h3 id=\"css-parser\">CSS Parser</h3>\n                <p class=\"content en\">Parse and manipulate CSS programmatically:</p>\n                <p class=\"content ko\">CSS를 프로그래밍 방식으로 파싱하고 조작하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; CssParser, StyleRule, AtRule &#125; from '@dooboostore/core/parser/css/CssParser';\n\nconst cssString = `\n  body &#123;\n    font-family: Arial, sans-serif;\n    margin: 0;\n  &#125;\n  \n  @media (max-width: 600px) &#123;\n    .container &#123; width: 100%; &#125;\n  &#125;\n`;\n\nconst parser = new CssParser(cssString);\n\n// Find and modify rules\nconst bodyRule = parser.rules.find(rule =&gt; \n  rule instanceof StyleRule && rule.selector === 'body'\n) as StyleRule;\n\nif (bodyRule) &#123;\n  // Add new declaration\n  bodyRule.content.push(&#123; \n    type: 'declaration', \n    property: 'color', \n    value: '&#35;333' \n  &#125;);\n&#125;\n\n// Add new rule\nparser.append('.footer &#123; text-align: center; &#125;');\n\nconsole.log(parser.stringify());</code></pre>\n                </div>\n\n                <h3 id=\"geometry-rendering\">2D/3D Geometry & Rendering</h3>\n                <p class=\"content en\">Comprehensive geometry classes with rendering capabilities:</p>\n                <p class=\"content ko\">렌더링 기능을 포함한 포괄적인 기하학 클래스:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; Point2D, Vector, Rect, Polygon &#125; from '@dooboostore/core/entity';\n\n// 2D Points and Vectors\nconst point1 = new Point2D(10, 20);\nconst point2 = new Point2D(30, 40);\nconst vector = new Vector(point1, point2);\n\nconsole.log(vector.magnitude()); // Distance between points\nconsole.log(vector.angle()); // Angle in radians\n\n// Rectangle operations\nconst rect = new Rect(0, 0, 100, 50);\nconst centerPoint = new Point2D(50, 25);\nconsole.log(rect.contains(centerPoint)); // true\n\n// Polygon operations\nconst triangle = new Polygon([\n  new Point2D(0, 0),\n  new Point2D(50, 0),\n  new Point2D(25, 50)\n]);\n\nconst testPoint = new Point2D(25, 20);\nconsole.log(triangle.contains(testPoint)); // true\n\n// Collision detection\nconst rect2 = new Rect(50, 25, 100, 50);\nconsole.log(rect.overlaps(rect2)); // true</code></pre>\n                </div>\n\n                <h3 id=\"promise-utilities\">Promise Utilities</h3>\n                <p class=\"content en\">Advanced Promise handling and state management:</p>\n                <p class=\"content ko\">고급 Promise 처리 및 상태 관리:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">import &#123; Promises &#125; from '@dooboostore/core/promise/Promises';\n\n// Sleep utility\nawait Promises.sleep(1000); // Wait 1 second\n\n// Polling with loop\nconst result = await Promises.loop(\n  async () =&gt; &#123;\n    const response = await fetch('/api/status');\n    return response.json();\n  &#125;,\n  (data) =&gt; data.status === 'complete', // Continue until complete\n  &#123; interval: 1000, maxAttempts: 10 &#125;\n);\n\n// Transaction management\nconst transaction = Promises.transaction();\ntry &#123;\n  const user = await transaction.add(() =&gt; createUser(userData));\n  const profile = await transaction.add(() =&gt; createProfile(user.id));\n  await transaction.commit();\n&#125; catch (error) &#123;\n  await transaction.rollback(); // Undo all operations\n&#125;\n\n// Result wrapper for safe error handling\nconst safeResult = await Promises.Result.wrap(riskyOperation());\nif (safeResult.isSuccess()) &#123;\n  console.log('Success:', safeResult.data);\n&#125; else &#123;\n  console.error('Error:', safeResult.error);\n&#125;</code></pre>\n                </div>\n            </section>\n\n            <!-- Core Concepts -->\n            <section class=\"section\">\n                <h2 id=\"core-concepts\">Core Concepts</h2>\n                <div class=\"concepts-grid\">\n                    <div class=\"concept-item\">\n                        <h4>Utility-First Design</h4>\n                        <p class=\"content en\">Modular utilities that can be imported individually for optimal bundle size</p>\n                        <p class=\"content ko\">최적의 번들 크기를 위해 개별적으로 가져올 수 있는 모듈식 유틸리티</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Type Safety</h4>\n                        <p class=\"content en\">Comprehensive TypeScript support with advanced utility types</p>\n                        <p class=\"content ko\">고급 유틸리티 타입을 포함한 포괄적인 TypeScript 지원</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Reactive Programming</h4>\n                        <p class=\"content en\">Observable pattern with RxJS-compatible operators for data streams</p>\n                        <p class=\"content ko\">데이터 스트림을 위한 RxJS 호환 연산자를 포함한 Observable 패턴</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Asynchronous Patterns</h4>\n                        <p class=\"content en\">Advanced Promise utilities for complex async workflows</p>\n                        <p class=\"content ko\">복잡한 비동기 워크플로우를 위한 고급 Promise 유틸리티</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Geometry & Rendering</h4>\n                        <p class=\"content en\">Complete 2D/3D geometry system with collision detection and rendering</p>\n                        <p class=\"content ko\">충돌 감지와 렌더링을 포함한 완전한 2D/3D 기하학 시스템</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Extensible Architecture</h4>\n                        <p class=\"content en\">Base classes and interfaces for building custom components</p>\n                        <p class=\"content ko\">커스텀 컴포넌트 구축을 위한 기본 클래스와 인터페이스</p>\n                    </div>\n                </div>\n            </section>\n        </div>\n    </div>\n</div>");

