/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("* {\n    margin: 0;\n    padding: 0;\n    box-sizing: border-box;\n}\n\n.package-container {\n    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;\n    background: #0a0a0a;\n    color: #e5e5e5;\n    min-height: 100vh;\n}\n\n.container {\n    max-width: 1200px;\n    margin: 0 auto;\n    padding: 0 2rem;\n}\n\n/* Header */\n.package-header {\n    background: linear-gradient(135deg, #0a0a0a 0%, #1a1a1a 100%);\n    padding: 3rem 0;\n    border-bottom: 1px solid #2a2a2a;\n}\n\n.package-header h1 {\n    font-size: 2.5rem;\n    font-weight: 300;\n    margin-bottom: 1rem;\n    color: #ffffff;\n    letter-spacing: -0.02em;\n    font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;\n}\n\n.package-actions {\n    margin-top: 0.5rem;\n    display: flex;\n    gap: 24px;\n    flex-wrap: wrap;\n    align-items: center;\n}\n\n.package-link {\n    color: rgba(255, 255, 255, 0.7);\n    text-decoration: none;\n    font-size: 14px;\n    font-weight: 500;\n    display: flex;\n    align-items: center;\n    gap: 6px;\n    transition: color 0.2s ease;\n}\n\n.package-link:hover {\n    color: white;\n}\n\n.package-link i {\n    font-size: 16px;\n}\n\n/* Content */\n.package-content {\n    padding: 4rem 0;\n}\n\n.section {\n    margin-bottom: 4rem;\n}\n\n.section h2 {\n    font-size: 1.75rem;\n    font-weight: 400;\n    color: #ffffff;\n    margin-bottom: 2rem;\n    padding: 1rem 0 0.5rem 0;\n    border-bottom: 1px solid #2a2a2a;\n    position: sticky;\n    top: 100px;\n    background: rgba(10, 10, 10, 0.98);\n    backdrop-filter: blur(12px);\n    z-index: 10;\n    border-top: 1px solid transparent;\n}\n\n.section h3 {\n    font-size: 1.25rem;\n    font-weight: 500;\n    color: #ffffff;\n    margin: 2rem 0 1rem 0;\n}\n\n.section h4 {\n    font-size: 1rem;\n    font-weight: 500;\n    color: #ffffff;\n    margin-bottom: 0.5rem;\n}\n\n/* Code Examples */\n.code-example {\n    background: #1a1a1a;\n    border: 1px solid #2a2a2a;\n    border-radius: 8px;\n    overflow: hidden;\n    margin-bottom: 1.5rem;\n}\n\n.code-header {\n    background: #2a2a2a;\n    padding: 0.75rem 1.5rem;\n    border-bottom: 1px solid #3a3a3a;\n}\n\n.code-title {\n    font-size: 0.875rem;\n    font-weight: 500;\n    color: #e5e5e5;\n}\n\n.code-example pre {\n    padding: 1.5rem;\n    margin: 0;\n    overflow-x: auto;\n    background: transparent;\n}\n\n.code-example code {\n    color: #e5e5e5;\n    font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;\n    font-size: 0.875rem;\n    line-height: 1.6;\n}\n\n/* Features Grid */\n.features-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));\n    gap: 1.5rem;\n    margin-top: 1.5rem;\n}\n\n.feature-item {\n    background: #1a1a1a;\n    border: 1px solid #2a2a2a;\n    border-radius: 8px;\n    padding: 1.5rem;\n}\n\n.feature-item h3 {\n    font-size: 1.1rem;\n    font-weight: 500;\n    color: #ffffff;\n    margin-bottom: 0.75rem;\n}\n\n.feature-item p {\n    color: #a0a0a0;\n    line-height: 1.5;\n    font-size: 0.9rem;\n}\n\n/* Concepts Grid */\n.concepts-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));\n    gap: 1.5rem;\n    margin-top: 1.5rem;\n}\n\n.concept-item {\n    background: #1a1a1a;\n    border: 1px solid #2a2a2a;\n    border-radius: 8px;\n    padding: 1.5rem;\n}\n\n.concept-item h4 {\n    font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;\n    color: #ffffff;\n    margin-bottom: 0.75rem;\n    font-size: 1rem;\n}\n\n.concept-item p {\n    color: #a0a0a0;\n    line-height: 1.5;\n    font-size: 0.9rem;\n}\n\n/* Directive Grid */\n.directive-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));\n    gap: 1.5rem;\n    margin-top: 1.5rem;\n}\n\n.directive-item {\n    background: #1a1a1a;\n    border: 1px solid #2a2a2a;\n    border-radius: 8px;\n    padding: 1.5rem;\n}\n\n.directive-item h4 {\n    font-family: 'Monaco', 'Menlo', 'Ubuntu Mono', monospace;\n    color: #ffffff;\n    margin-bottom: 0.75rem;\n    font-size: 0.95rem;\n}\n\n.directive-item p {\n    color: #a0a0a0;\n    line-height: 1.5;\n    font-size: 0.85rem;\n}\n\n/* Responsive */\n@media (max-width: 768px) {\n    .package-header {\n        padding: 2rem 0;\n    }\n    \n    .package-header h1 {\n        font-size: 2rem;\n    }\n    \n    .package-content {\n        padding: 3rem 0;\n    }\n    \n    .section {\n        margin-bottom: 3rem;\n    }\n    \n    .features-grid,\n    .concepts-grid,\n    .directive-grid {\n        grid-template-columns: 1fr;\n    }\n    \n    .package-actions {\n        gap: 16px;\n        flex-wrap: wrap;\n    }\n    \n    .package-link {\n        font-size: 13px;\n    }\n}/* \nMobile code fix */\n@media (max-width: 768px) {\n    .container {\n        padding: 0 1rem;\n    }\n    \n    /*.code-example {*/\n    /*    margin: 0 -1rem 1.5rem -1rem;*/\n    /*    border-radius: 0;*/\n    /*}*/\n    \n    .code-example pre {\n        padding: 1rem;\n        overflow-x: auto;\n        font-size: 0.8rem;\n    }\n    \n    /*.section h2 {*/\n    /*    top: 90px;*/\n    /*    margin: -1rem -1rem -1rem -1rem;*/\n    /*    padding-left: 0.5rem;*/\n    /*}*/\n}");

