/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"package-container\">\n    <div class=\"package-header\">\n        <div class=\"container\">\n            <h1>simple-boot-front</h1>\n            <p class=\"content en\">Single Page Application framework for web development</p>\n            <p class=\"content ko\">웹 개발을 위한 단일 페이지 애플리케이션 프레임워크</p>\n            <div class=\"package-actions\">\n                <a href=\"https://github.com/dooboostore-develop/packages\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n                </a>\n                <a href=\"https://www.npmjs.com/package/@dooboostore/simple-boot-front\" target=\"_blank\" rel=\"noopener noreferrer\">\n                    <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n                </a>\n            </div>\n        </div>\n    </div>\n    <div class=\"package-content\">\n        <div class=\"container\">\n            <!-- Installation -->\n            <section class=\"section\">\n                <h2 id=\"installation\">Installation</h2>\n                <p class=\"content en\">Install the package and its dependencies:</p>\n                <p class=\"content ko\">패키지와 의존성을 설치하세요:</p>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">npm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">npm install @dooboostore/simple-boot-front reflect-metadata</code></pre>\n                </div>\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">pnpm</span>\n                    </div>\n                    <pre><code class=\"language-bash\">pnpm add @dooboostore/simple-boot-front reflect-metadata</code></pre>\n                </div>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">Quick Start CLI</span>\n                    </div>\n                    <pre><code class=\"language-bash\">npm init @dooboostore/simple-boot-front projectname\ncd projectname\nnpm start</code></pre>\n                </div>\n            </section>\n\n            <!-- Features -->\n            <section class=\"section\">\n                <h2 id=\"features\">Features</h2>\n                <div class=\"features-grid\">\n                    <div class=\"feature-item\">\n                        <h3>SPA Framework</h3>\n                        <p class=\"content en\">Complete Single Page Application framework for modern web development</p>\n                        <p class=\"content ko\">현대적인 웹 개발을 위한 완전한 단일 페이지 애플리케이션 프레임워크</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Component System</h3>\n                        <p class=\"content en\">Decorator-based component system with template and style support</p>\n                        <p class=\"content ko\">템플릿과 스타일을 지원하는 데코레이터 기반 컴포넌트 시스템</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Router System</h3>\n                        <p class=\"content en\">Flexible routing with path parameters and route guards</p>\n                        <p class=\"content ko\">경로 매개변수와 라우트 가드를 지원하는 유연한 라우팅</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Dependency Injection</h3>\n                        <p class=\"content en\">Built on simple-boot core with full DI and AOP support</p>\n                        <p class=\"content ko\">완전한 DI와 AOP를 지원하는 simple-boot 코어 기반</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Template Engine</h3>\n                        <p class=\"content en\">Powered by dom-render for efficient DOM manipulation</p>\n                        <p class=\"content ko\">효율적인 DOM 조작을 위한 dom-render 기반</p>\n                    </div>\n                    <div class=\"feature-item\">\n                        <h3>Script System</h3>\n                        <p class=\"content en\">Custom script system for reusable template logic</p>\n                        <p class=\"content ko\">재사용 가능한 템플릿 로직을 위한 커스텀 스크립트 시스템</p>\n                    </div>\n                </div>\n            </section>\n\n            <!-- Quick Start -->\n            <section class=\"section\">\n                <h2 id=\"quick-start\">Quick Start</h2>\n                \n                <h3 id=\"basic-setup\">Basic Setup</h3>\n                <p class=\"content en\">Create a simple SPA with routing:</p>\n                <p class=\"content ko\">라우팅을 포함한 간단한 SPA를 생성하세요:</p>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">pages/home.ts</span>\n                    </div>\n                    <pre><code class=\"language-typescript\">@Sim\n@Component({\n    template: '<div>Home Page</div>'\n})\nexport class Home {\n    \n}</code></pre>\n                </div>\n\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">pages/user.ts</span>\n                    </div>\n                    <pre><code class=\"language-typescript\">@Sim\n@Component({\n    template: '<div>User Page</div>'\n})\nexport class User {\n    \n}</code></pre>\n                </div>\n\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">index.ts</span>\n                    </div>\n                    <pre><code class=\"language-typescript\">import template from './index.html'\nimport style from './index.css'\n\n@Sim\n@Router({\n  path: '',\n  route: {\n    '/': Home,\n    '/user': User\n  }\n})\n@Component({\n  template,\n  styles: [style]\n})\nexport class Index implements RouterAction {\n  child?: any;\n  \n  async canActivate(url: any, module: any) {\n    this.child = module;\n  }\n}\n\nconst config = new SimFrontOption(window).setUrlType(UrlType.hash);\nconst simpleApplication = new SimpleBootFront(Index, config);\nsimpleApplication.run();</code></pre>\n                </div>\n\n                <h3 id=\"component-system\">Component System</h3>\n                <p class=\"content en\">Create reusable components with templates and styles:</p>\n                <p class=\"content ko\">템플릿과 스타일을 포함한 재사용 가능한 컴포넌트를 생성하세요:</p>\n                \n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">template.html</span>\n                    </div>\n                    <pre><code class=\"language-html\">&lt;h1&gt;${this.title}&lt;/h1&gt;\n&lt;div&gt;#innerHTML#&lt;/div&gt;</code></pre>\n                </div>\n\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">component.ts</span>\n                    </div>\n                    <pre><code class=\"language-typescript\">import template from './template.html'\nimport style from './style.css'\n\n@Sim\n@Component({\n  selector: 'my-component', // default: class name lowercase\n  template,\n  styles: [style]\n})\nexport class MyComponent {\n  public title = 'Hello Component'\n  \n  public setData(title: string) {\n    this.title = title;\n  }\n}</code></pre>\n                </div>\n\n                <div class=\"code-example\">\n                    <div class=\"code-header\">\n                        <span class=\"code-title\">Usage in template</span>\n                    </div>\n                    <pre><code class=\"language-html\">&lt;my-component&gt;&lt;/my-component&gt;\n\n&lt;!-- With data binding --&gt;\n&lt;my-component dr-set=\"$myComponent.setData('Dynamic Title')\"&gt;\n  &lt;ul&gt;\n    &lt;li&gt;Custom content&lt;/li&gt;\n  &lt;/ul&gt;\n&lt;/my-component&gt;</code></pre>\n                </div>\n\n                <h3 id=\"routing-example\">Advanced Routing</h3>\n                <p class=\"content en\">Handle dynamic routes with path parameters:</p>\n                <p class=\"content ko\">경로 매개변수를 사용한 동적 라우팅을 처리하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">@Sim\n@Router({\n    path: '',\n    route: {\n        '/': Home,\n        '/user': User,\n        '/user/{id}': UserDetail\n    }\n})\n@Component({\n    template,\n    styles: [style]\n})\nexport class AppRouter implements RouterAction {\n    child?: any;\n    \n    canActivate(url: any, module: any): void {\n        this.child = module;\n    }\n}\n\n// Access path parameters\n@Sim\nexport class UserDetail {\n    constructor(private routerManager: RouterManager) {\n        // Get path data: /user/123 -> { id: '123' }\n        const userId = routerManager.activeRouterModule.pathData.id;\n        console.log('User ID:', userId);\n    }\n}</code></pre>\n                </div>\n            </section>\n\n            <!-- Advanced Features -->\n            <section class=\"section\">\n                <h2 id=\"advanced-features\">Advanced Features</h2>\n                \n                <h3 id=\"script-system\">Script System</h3>\n                <p class=\"content en\">Create reusable template scripts for common functionality:</p>\n                <p class=\"content ko\">공통 기능을 위한 재사용 가능한 템플릿 스크립트를 생성하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">@Sim({scheme: 'i18nScript'})\n@Script({\n    name: 'i18n'\n})\nexport class I18nScript extends ScriptRunnable {\n    public language?: Language;\n    \n    constructor(public i18nService: I18nService) {\n        super();\n        i18nService.subject.subscribe(it => {\n            this.language = it;\n            this.render();  // Re-render components using this script\n        })\n    }\n    \n    run(key: string): any {\n        return this.language?.defaultData?.[key] ?? key;\n    }\n}\n\n// Usage in templates\n// &lt;div&gt;${$scripts.i18n('Get Locale JSON')}&lt;/div&gt;\n// &lt;div dr-if=\"$scripts.i18n('Get Locale JSON') === 'wow'\"&gt; is wow&lt;/div&gt;</code></pre>\n                </div>\n\n                <h3 id=\"lifecycle-hooks\">Lifecycle Hooks</h3>\n                <p class=\"content en\">Hook into component lifecycle events:</p>\n                <p class=\"content ko\">컴포넌트 생명주기 이벤트에 연결하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">@Sim\n@Component({\n    template: '&lt;div&gt;Lifecycle Component&lt;/div&gt;'\n})\nexport class LifecycleComponent implements OnInit, OnDestroy, OnChangedRender {\n    \n    @PostConstruct\n    postConstruct(projectService: ProjectService) {\n        console.log('Post construct with DI');\n    }\n    \n    onInit(): void {\n        console.log('Component initialized');\n    }\n    \n    onChangedRender(): void {\n        console.log('Component re-rendered');\n    }\n    \n    onDestroy(): void {\n        console.log('Component destroyed');\n    }\n}</code></pre>\n                </div>\n\n                <h3 id=\"aop-support\">AOP Support</h3>\n                <p class=\"content en\">Use Aspect-Oriented Programming for cross-cutting concerns:</p>\n                <p class=\"content ko\">횡단 관심사를 위한 관점 지향 프로그래밍을 사용하세요:</p>\n                \n                <div class=\"code-example\">\n                    <pre><code class=\"language-typescript\">@Sim\n@Component({\n    template: '&lt;button dr-event-click=\"fire($event, $view)\"&gt;Click me&lt;/button&gt;'\n})\nexport class AopComponent {\n    data = 0;\n    \n    fire($event: MouseEvent, view: View&lt;Element&gt;) {\n        console.log('fire method');\n        this.data = RandomUtils.random(0, 100);\n    }\n\n    @Before({property: 'fire'})\n    before(obj: any, protoType: Function) {\n        console.log('before fire method', obj, protoType);\n    }\n\n    @After({property: 'fire'})\n    after(obj: any, protoType: Function) {\n        console.log('after fire method', obj, protoType);\n    }\n}</code></pre>\n                </div>\n            </section>\n\n            <!-- Core Concepts -->\n            <section class=\"section\">\n                <h2 id=\"core-concepts\">Core Concepts</h2>\n                <div class=\"concepts-grid\">\n                    <div class=\"concept-item\">\n                        <h4>@Component</h4>\n                        <p class=\"content en\">Decorator for creating reusable UI components with templates and styles</p>\n                        <p class=\"content ko\">템플릿과 스타일을 포함한 재사용 가능한 UI 컴포넌트 생성 데코레이터</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>@Router</h4>\n                        <p class=\"content en\">Routing system that maps URLs to components with path parameters</p>\n                        <p class=\"content ko\">경로 매개변수를 포함하여 URL을 컴포넌트에 매핑하는 라우팅 시스템</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>@Script</h4>\n                        <p class=\"content en\">Custom script system for reusable template logic and utilities</p>\n                        <p class=\"content ko\">재사용 가능한 템플릿 로직과 유틸리티를 위한 커스텀 스크립트 시스템</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>SimpleBootFront</h4>\n                        <p class=\"content en\">Main application class that bootstraps the SPA framework</p>\n                        <p class=\"content ko\">SPA 프레임워크를 부트스트랩하는 메인 애플리케이션 클래스</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>DOM Render Engine</h4>\n                        <p class=\"content en\">Efficient DOM manipulation and template rendering system</p>\n                        <p class=\"content ko\">효율적인 DOM 조작과 템플릿 렌더링 시스템</p>\n                    </div>\n                    <div class=\"concept-item\">\n                        <h4>Lifecycle Management</h4>\n                        <p class=\"content en\">Component lifecycle hooks for initialization, rendering, and cleanup</p>\n                        <p class=\"content ko\">초기화, 렌더링, 정리를 위한 컴포넌트 생명주기 훅</p>\n                    </div>\n                </div>\n            </section>\n        </div>\n    </div>\n</div>");

