/* harmony default export */ const __WEBPACK_DEFAULT_EXPORT__ = ("<div class=\"package-container\">\n  <div class=\"package-header\">\n    <div class=\"container\">\n      <h1>simple-boot</h1>\n      <p class=\"content en\">Lightweight framework with DI and AOP support</p>\n      <p class=\"content ko\">DI, AOP를 지원하는 경량 프레임워크</p>\n      <div class=\"package-actions\">\n          <a href=\"https://github.com/dooboostore-develop/packages\" target=\"_blank\" rel=\"noopener noreferrer\">\n              <img src=\"https://img.shields.io/badge/Github-555555?style=flat&logo=github&logoColor=white\" alt=\"GitHub\"/>\n          </a>\n          <a href=\"https://www.npmjs.com/package/@dooboostore/simple-boot\" target=\"_blank\" rel=\"noopener noreferrer\">\n              <img src=\"https://img.shields.io/badge/Npm-cc0000?style=flat&logo=npm&logoColor=white\" alt=\"NPM\"/>\n          </a>\n      </div>\n    </div>\n  </div>\n  <div class=\"package-content\">\n    <div class=\"container\">\n      <!-- Installation -->\n      <section class=\"section\">\n        <h2 id=\"installation\">Installation</h2>\n        <p class=\"content en\">Install the package and its peer dependency:</p>\n        <p class=\"content ko\">패키지와 필수 의존성을 설치하세요:</p>\n\n        <div class=\"code-example\">\n          <div class=\"code-header\">\n            <span class=\"code-title\">npm</span>\n          </div>\n          <pre><code class=\"language-bash\">npm install @dooboostore/simple-boot reflect-metadata</code></pre>\n        </div>\n        <div class=\"code-example\">\n          <div class=\"code-header\">\n            <span class=\"code-title\">pnpm</span>\n          </div>\n          <pre><code class=\"language-bash\">pnpm add @dooboostore/simple-boot reflect-metadata</code></pre>\n        </div>\n\n        <div class=\"code-example\">\n          <div class=\"code-header\">\n            <span class=\"code-title\">Quick Start CLI</span>\n          </div>\n          <pre><code class=\"language-bash\">npm init @dooboostore/simple-boot projectname\ncd projectname\nnpm start</code></pre>\n        </div>\n      </section>\n\n      <!-- Features -->\n      <section class=\"section\">\n        <h2 id=\"features\">Features</h2>\n        <div class=\"features-grid\">\n          <div class=\"feature-item\">\n            <h3>Object Management</h3>\n            <p class=\"content en\">Dependency Injection (DI) and Lifecycle callbacks</p>\n            <p class=\"content ko\">의존성 주입(DI)과 생명주기 콜백</p>\n          </div>\n          <div class=\"feature-item\">\n            <h3>Aspect-Oriented Programming</h3>\n            <p class=\"content en\">AOP support with @Before, @After, @Around decorators</p>\n            <p class=\"content ko\">@Before, @After, @Around 데코레이터를 통한 AOP 지원</p>\n          </div>\n          <div class=\"feature-item\">\n            <h3>Exception Handling</h3>\n            <p class=\"content en\">Powerful global and local exception handling</p>\n            <p class=\"content ko\">강력한 전역 및 지역 예외 처리</p>\n          </div>\n          <div class=\"feature-item\">\n            <h3>Flexible Router System</h3>\n            <p class=\"content en\">Class-based and method-based routing</p>\n            <p class=\"content ko\">클래스 기반 및 메서드 기반 라우팅</p>\n          </div>\n          <div class=\"feature-item\">\n            <h3>Intent Event System</h3>\n            <p class=\"content en\">Decoupled communication with Intent objects</p>\n            <p class=\"content ko\">Intent 객체를 통한 분리된 통신</p>\n          </div>\n          <div class=\"feature-item\">\n            <h3>Method-level Caching</h3>\n            <p class=\"content en\">Built-in caching with TTL and dynamic keys</p>\n            <p class=\"content ko\">TTL과 동적 키를 지원하는 내장 캐싱</p>\n          </div>\n          <div class=\"feature-item\">\n            <h3>Data Validation</h3>\n            <p class=\"content en\">Property validation with decorators</p>\n            <p class=\"content ko\">데코레이터를 통한 속성 검증</p>\n          </div>\n        </div>\n      </section>\n\n      <!-- Quick Start -->\n      <section class=\"section\">\n        <h2 id=\"quick-start\">Quick Start</h2>\n\n        <h3 id=\"basic-usage\">Basic Usage</h3>\n        <p class=\"content en\">Here's a simple example to get you started:</p>\n        <p class=\"content ko\">시작하기 위한 간단한 예제입니다:</p>\n\n        <div class=\"code-example\">\n          <pre><code class=\"language-typescript\">import 'reflect-metadata';\nimport { SimpleApplication, Sim, Router } from '@dooboostore/simple-boot';\n\n@Sim // Decorator can be used without parentheses\nclass Greeter {\n  say() {\n    console.log('Hello, Simple Boot!');\n  }\n}\n\n@Sim\n@Router({ path: '', route: { '/user': Greeter } })\nclass AppRouter {}\n\nconst app = new SimpleApplication({ rootRouter: AppRouter });\napp.run();\n\n// Get instance and call method\nconst greeter = app.sim(Greeter);\ngreeter?.say();\n\n// Or, route to the module and execute\napp.routing('/user').then(routerModule => {\n    routerModule.getModuleInstance<Greeter>()?.say();\n});</code></pre>\n        </div>\n\n        <h3 id=\"dependency-injection\">Dependency Injection</h3>\n        <p class=\"content en\">Simple Boot automatically handles dependency injection based on constructor parameter\n          types:</p>\n        <p class=\"content ko\">Simple Boot은 생성자 매개변수 타입을 기반으로 의존성 주입을 자동으로 처리합니다:</p>\n\n        <div class=\"code-example\">\n          <pre><code class=\"language-typescript\">@Sim // Using without parentheses for default settings\nclass ProjectService {\n  sum(x: number, y: number): number {\n    return x + y;\n  }\n}\n\n@Sim() // Using with parentheses is also valid\nclass User {\n  constructor(private projectService: ProjectService) {}\n\n  calculate() {\n    const result = this.projectService.sum(5, 25);\n    console.log(`Calculation result is: ${result}`);\n  }\n}\n\n// somewhere in your app\nconst user = app.sim(User);\nuser?.calculate(); //-> Calculation result is: 30</code></pre>\n        </div>\n\n        <h3 id=\"lifecycle-management\">Lifecycle Management</h3>\n        <p class=\"content en\">Control object lifecycle with Singleton and Transient scopes:</p>\n        <p class=\"content ko\">Singleton과 Transient 스코프로 객체 생명주기를 제어하세요:</p>\n\n        <div class=\"code-example\">\n          <pre><code class=\"language-typescript\">import { Sim, Lifecycle } from '@dooboostore/simple-boot';\n\n// Singleton (Default) - Same instance every time\n@Sim({\n  scope: Lifecycle.Singleton\n})\nclass DatabaseService {\n  private connection = 'db-connection';\n  \n  getConnection() {\n    return this.connection;\n  }\n}\n\n// Transient - A new instance is created on each request\n@Sim({\n  scope: Lifecycle.Transient\n})\nclass RequestHandler {\n  private requestId = Math.random();\n  \n  getId() {\n    return this.requestId;\n  }\n}</code></pre>\n        </div>\n\n        <h3 id=\"aop-example\">AOP Example</h3>\n        <p class=\"content en\">Use AOP decorators to intercept method calls:</p>\n        <p class=\"content ko\">AOP 데코레이터를 사용하여 메서드 호출을 가로채세요:</p>\n\n        <div class=\"code-example\">\n          <pre><code class=\"language-typescript\">import { Sim, Before, After, Around, AroundForceReturn } from '@dooboostore/simple-boot';\n\nconst LoggingAround = () => Around({\n    before: (obj, propertyKey, args) => {\n        console.log(`[${propertyKey}] Before with args:`, args);\n        // You can modify arguments here\n        return args.map(arg => typeof arg === 'number' ? arg * 2 : arg);\n    },\n    after: (obj, propertyKey, args, beforeReturn) => {\n        console.log(`[${propertyKey}] After with result:`, beforeReturn);\n        // You can force a different return value\n        if (beforeReturn > 10) {\n            throw new AroundForceReturn(\"Value is too high!\");\n        }\n        return beforeReturn;\n    }\n});\n\n@Sim\nclass Calculator {\n    @Before({ property: 'add' })\n    logBefore() {\n        console.log('Preparing to add...');\n    }\n\n    @After({ property: 'add' })\n    logAfter() {\n        console.log('Addition complete.');\n    }\n\n    @LoggingAround()\n    add(a: number, b: number): number {\n        console.log('Executing add method');\n        return a + b;\n    }\n}</code></pre>\n        </div>\n      </section>\n\n      <!-- Advanced Features -->\n      <section class=\"section\">\n        <h2 id=\"advanced-features\">Advanced Features</h2>\n\n        <h3 id=\"exception-handling\">Exception Handling</h3>\n        <p class=\"content en\">Handle exceptions locally or globally with @ExceptionHandler:</p>\n        <p class=\"content ko\">@ExceptionHandler로 예외를 지역적 또는 전역적으로 처리하세요:</p>\n\n        <div class=\"code-example\">\n          <pre><code class=\"language-typescript\">class MyError extends Error {}\n\n@Sim\nclass UserService {\n  @ExceptionHandler({ type: MyError })\n  handleMyError(e: MyError) {\n    console.error(`Caught a specific MyError: ${e.message}`);\n  }\n\n  @ExceptionHandler()\n  handleAllOtherErrors(e: any) {\n    console.error(`Caught a generic error:`, e);\n  }\n\n  doSomething() {\n    throw new MyError('Something went wrong!');\n  }\n}</code></pre>\n        </div>\n\n        <h3 id=\"caching\">Caching</h3>\n        <p class=\"content en\">Cache method results with @Cache decorator:</p>\n        <p class=\"content ko\">@Cache 데코레이터로 메서드 결과를 캐시하세요:</p>\n\n        <div class=\"code-example\">\n          <pre><code class=\"language-typescript\">@Sim\nclass UserService {\n    @Cache({ key: (id: string) => `user:${id}`, ms: 5000 }) // Dynamic key, 5-second TTL\n    getUserById(id: string) {\n        console.log(`Fetching user ${id} from DB...`);\n        return { id, name: 'User ' + id };\n    }\n\n    @Cache({ deleteKey: (id: string) => `user:${id}` })\n    updateUser(id: string, data: any) {\n        console.log(`Updating user ${id}, cache will be cleared.`);\n        // ... update logic\n    }\n}</code></pre>\n        </div>\n\n        <h3 id=\"validation\">Validation</h3>\n        <p class=\"content en\">Validate class properties with decorators:</p>\n        <p class=\"content ko\">데코레이터로 클래스 속성을 검증하세요:</p>\n\n        <div class=\"code-example\">\n          <pre><code class=\"language-typescript\">import { Sim, Validation, NotEmpty, NotNull, Regexp, execValidationInValid, ValidException } from '@dooboostore/simple-boot';\n\n@Sim\nclass UserProfile {\n    @Validation(NotEmpty)\n    @Validation(Regexp(/^[a-zA-Z]+$/))\n    name: string = '';\n\n    @Validation(NotNull)\n    age: number | null = null;\n}\n\nconst profile = new UserProfile();\nprofile.name = '123'; // Invalid name\nprofile.age = null; // Invalid age\n\nconst validationErrors = execValidationInValid(profile);\n\nif (validationErrors.length > 0) {\n    throw new ValidException(validationErrors);\n}</code></pre>\n        </div>\n      </section>\n\n      <!-- Core Concepts -->\n      <section class=\"section\">\n        <h2 id=\"core-concepts\">Core Concepts</h2>\n        <div class=\"concepts-grid\">\n          <div class=\"concept-item\">\n            <h4>@Sim</h4>\n            <p class=\"content en\">Core decorator that marks a class for management by the Simple Boot container</p>\n            <p class=\"content ko\">Simple Boot 컨테이너에서 관리할 클래스를 표시하는 핵심 데코레이터</p>\n          </div>\n          <div class=\"concept-item\">\n            <h4>SimpleApplication</h4>\n            <p class=\"content en\">Application entry point that initializes and manages the DI container</p>\n            <p class=\"content ko\">DI 컨테이너를 초기화하고 관리하는 애플리케이션 진입점</p>\n          </div>\n          <div class=\"concept-item\">\n            <h4>@Router & @Route</h4>\n            <p class=\"content en\">Routing system that maps URL paths to classes or methods</p>\n            <p class=\"content ko\">URL 경로를 클래스나 메서드에 매핑하는 라우팅 시스템</p>\n          </div>\n          <div class=\"concept-item\">\n            <h4>@Before/@After/@Around</h4>\n            <p class=\"content en\">AOP decorators for intercepting method calls</p>\n            <p class=\"content ko\">메서드 호출을 가로채는 AOP 데코레이터</p>\n          </div>\n          <div class=\"concept-item\">\n            <h4>Intent System</h4>\n            <p class=\"content en\">Event system for decoupled communication between components</p>\n            <p class=\"content ko\">컴포넌트 간 분리된 통신을 위한 이벤트 시스템</p>\n          </div>\n          <div class=\"concept-item\">\n            <h4>@Cache</h4>\n            <p class=\"content en\">Method-level caching with TTL and dynamic key support</p>\n            <p class=\"content ko\">TTL과 동적 키를 지원하는 메서드 레벨 캐싱</p>\n          </div>\n        </div>\n      </section>\n    </div>\n  </div>\n</div>");

